const fs = require('fs');
const vm = require('vm');
const { performance } = require('perf_hooks');

function makeContext() {
  const ctx = {
    console,
    setTimeout,
    setInterval,
    clearTimeout,
    clearInterval,
    performance,
    Math,
    Date,
  };
  // window alias
  ctx.window = {};
  // requestAnimationFrame: call cb async with timestamp
  ctx.requestAnimationFrame = function(cb) { return setTimeout(() => cb(performance.now()), 0); };
  return ctx;
}

function run() {
  const script = fs.readFileSync(__dirname + '/../game/dist/main.js', 'utf8');
  const ctx = makeContext();
  vm.createContext(ctx);
  // run the compiled main.js in the context; it assigns to window
  vm.runInContext(script, ctx);
  const w = ctx.window;
  if (typeof w.advanceTime !== 'function' || typeof w.render_game_to_text !== 'function') {
    throw new Error('hooks missing');
  }
  // advance 10s (enter medium phase expected)
  w.advanceTime(10000);
  const txt = w.render_game_to_text();
  if (!/score=\d+/.test(txt)) throw new Error('score missing');
  console.log('score text:', txt);
  const m = txt.match(/score=(\d+)/);
  const score = parseInt(m[1], 10);
  if (!(score > 0)) throw new Error('score not > 0');
  console.log('score test passed ->', score);
  // collision test
  w.__GAME.obstacles.push({ x: w.__GAME.playerX + 10, w:40, h:40 });
  w.advanceTime(10);
  const txt2 = w.render_game_to_text();
  console.log('post-collision text:', txt2);
  if (!txt2.includes('game_over=true')) throw new Error('collision failed');
  console.log('collision test passed');
  // phase transition checks
  // advance to just before medium
  const g = w.__GAME;
  g.time = 19990; g.obstacles = [];
  // clear game_over so updates proceed
  g.game_over = false; g.playerY = 0; g.playerVy = 0; g.spawnTimer = 0;
  w.advanceTime(5);
  const t1 = w.render_game_to_text();
  if (!t1.startsWith('phase=easy')) throw new Error('phase did not remain easy')
  // advance into medium
  w.advanceTime(10010);
  const t2 = w.render_game_to_text();
  if (!t2.startsWith('phase=medium')) throw new Error('phase did not transition to medium')
  // advance into hard
  w.advanceTime(40000);
  const t3 = w.render_game_to_text();
  if (!t3.startsWith('phase=hard')) throw new Error('phase did not transition to hard')
  console.log('phase tests passed')
}

try { run(); console.log('ALL OK'); process.exit(0);} catch (e) { console.error(e.stack); process.exit(2);}

// Compiled JS (handwritten from TS) - deterministic Dino
class Game {
  constructor() {
    this.playerX = 80;
    this.playerY = 0;
    this.playerVy = 0;
    this.gravity = -0.0015;
    this.groundY = 0;
    this.obstacles = [];
    this.time = 0;
    this.speed = 0.12;
    this.spawnTimer = 0;
    this.spawnInterval = 1500;
    this.game_over = false;
  }
  get phase(){ if (this.time<20000) return 'easy'; if (this.time<45000) return 'medium'; return 'hard'; }
  update(ms) {
    if (this.game_over) return;
    this.time += ms;
    // difficulty multipliers
    const p = this.phase;
    let speedMul = 1;
    let spawnMul = 1;
    if (p === 'easy') { speedMul = 1; spawnMul = 1; }
    else if (p === 'medium') { speedMul = 1.4; spawnMul = 1.3; }
    else if (p === 'hard') { speedMul = 1.9; spawnMul = 1.6; }
    this.playerVy += this.gravity * ms;
    this.playerY += this.playerVy * ms;
    if (this.playerY < this.groundY) {
      this.playerY = this.groundY;
      this.playerVy = 0;
    }
    for (const o of this.obstacles) {
      o.x -= this.speed * speedMul * ms;
    }
    this.spawnTimer += ms;
    const curSpawnInterval = Math.max(300, this.spawnInterval / spawnMul);
    if (this.spawnTimer >= curSpawnInterval) {
      this.spawnTimer -= curSpawnInterval;
      var w = 20 + (Math.floor(this.time / 1000) % 3) * 4;
      this.obstacles.push({ x: 700, w: w, h: 40 });
    }
    this.obstacles = this.obstacles.filter(o => o.x + o.w > -50);
    for (const o of this.obstacles) {
      const px = this.playerX;
      const py = this.playerY;
      const pw = 40;
      const ph = 40;
      const ox = o.x;
      const oy = 0;
      const ow = o.w;
      const oh = o.h;
      const overlapX = px < ox + ow && px + pw > ox;
      const overlapY = py < oy + oh && py + ph > oy;
      if (overlapX && overlapY) {
        this.game_over = true;
      }
    }
  }
  get score() { return Math.floor(this.time * this.speed); }
  render_text() {
    const obs = this.obstacles.map(o => `${Math.round(o.x)}:${o.w}x${o.h}`).join(',');
    return `phase=${this.phase} | P@${Math.round(this.playerX)},${Math.round(this.playerY)} | obstacles=${this.obstacles.length}:${obs} | score=${this.score} | game_over=${this.game_over}`;
  }
}
window.__GAME = new Game();
window.advanceTime = function(ms) { window.__GAME.update(ms); };
window.render_game_to_text = function() { return window.__GAME.render_text(); };
let last = performance.now();
function rafTick(t) {
  const dt = t - last; last = t; window.__GAME.update(dt); requestAnimationFrame(rafTick);
}
requestAnimationFrame(rafTick);
